   359 |   //      !((icmp ne (A & B), 0) & (icmp eq (A & D), E)).
   360 |   //
   361 |   // We currently handle the case of B, C, D, E are constant.
   362 |   //
   363 |   const APInt *BCst, *DCst, *OrigECst;
   364 |   if (!match(B, m_APInt(BCst)) || !match(D, m_APInt(DCst)) ||
   365 |       !match(E, m_APInt(OrigECst)))
