      };

      // For OR/AND operations with adjacent ranges, fold to a single range check.
      // For OR: (x == C) | ((x & D) == E) where ranges [C, C+Size1-1] and [E, E+Size2-1] are adjacent
      //   -> (x - Base) <u TotalSize
      // For AND: (x != C) & ((x & D) != E) where ranges are adjacent
      //   -> (x - (Base + TotalSize)) <u (-TotalSize)  [negated range check]
      if ((Mask & BMask_NotMixed)) {
        // Check if B and D are of the form ~(2^N - 1) (clear low N bits)
        // This is true if (~B + 1) is a power of 2
        APInt InvBPlus1 = ~*ConstB + 1;
        APInt InvDPlus1 = ~*ConstD + 1;
        if (InvBPlus1.isPowerOf2() && InvDPlus1.isPowerOf2()) {
          uint64_t N1 = InvBPlus1.logBase2();
          uint64_t N2 = InvDPlus1.logBase2();
          APInt Size1 = APInt(ConstB->getBitWidth(), 1ULL << N1);
          APInt Size2 = APInt(ConstD->getBitWidth(), 1ULL << N2);

          // Check if ranges are adjacent: C + Size1 == E or E + Size2 == C
          APInt End1 = *OldConstC + Size1;
          APInt End2 = *OldConstE + Size2;

          APInt Base, TotalSize;
          bool Found = false;

          if (End1 == *OldConstE) {
            Base = *OldConstC;
            TotalSize = Size1 + Size2;
            Found = true;
          } else if (End2 == *OldConstC) {
            Base = *OldConstE;
            TotalSize = Size1 + Size2;
            Found = true;
          }

          if (Found) {
            if (IsAnd) {
              // For AND (negated comparison), the result is the negation of the range check
              // (x in [Base, Base + TotalSize - 1]) -> (x - (Base + TotalSize)) <u (-TotalSize)
              APInt EndPlus1 = Base + TotalSize;
              APInt NegSize = -TotalSize;
              Value *Sub = Builder.CreateSub(
                  A, ConstantInt::get(A->getType(), EndPlus1));
              return Builder.CreateICmpULT(
                  Sub, ConstantInt::get(A->getType(), NegSize));
            } else {
              // For OR, the result is the range check directly
              Value *Sub = Builder.CreateSub(
                  A, ConstantInt::get(A->getType(), Base));
              return Builder.CreateICmpULT(
                  Sub, ConstantInt::get(A->getType(), TotalSize));
            }
          }
        }
      }

